#include <stdio.h>
#include <stdlib.h>

// Node structure for the binary tree
typedef struct Node {
    int data;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->data = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if a node is a leaf
int isLeaf(Node* root) {
    return !root->left && !root->right;
}

// Function to add the left boundary of the tree
void addLeftBoundary(Node* root, int* res, int* index) {
    Node* curr = root->left;
    while (curr) {
        if (!isLeaf(curr)) {
            res[(*index)++] = curr->data;
        }
        if (curr->left) {
            curr = curr->left;
        } else {
            curr = curr->right;
        }
    }
}

// Function to add the right boundary of the tree
void addRightBoundary(Node* root, int* res, int* index) {
    Node* curr = root->right;
    int temp[1000];
    int tempIndex = 0;
    while (curr) {
        if (!isLeaf(curr)) {
            temp[tempIndex++] = curr->data;
        }
        if (curr->right) {
            curr = curr->right;
        } else {
            curr = curr->left;
        }
    }
    for (int i = tempIndex - 1; i >= 0; --i) {
        res[(*index)++] = temp[i];
    }
}

// Function to add the leaves of the tree
void addLeaves(Node* root, int* res, int* index) {
    if (isLeaf(root)) {
        res[(*index)++] = root->data;
        return;
    }
    if (root->left) {
        addLeaves(root->left, res, index);
    }
    if (root->right) {
        addLeaves(root->right, res, index);
    }
}

// Function to perform the boundary traversal of the binary tree
void printBoundary(Node* root) {
    if (!root) {
        return;
    }
    int res[1000];
    int index = 0;
    if (!isLeaf(root)) {
        res[index++] = root->data;
    }
    addLeftBoundary(root, res, &index);
    addLeaves(root, res, &index);
    addRightBoundary(root, res, &index);
    for (int i = 0; i < index; ++i) {
        printf("%d ", res[i]);
    }
    printf("\n");
}

int main() {
    Node* root = createNode(1);
    root->left = createNode(2);
    root->right = createNode(3);
    root->left->left = createNode(4);
    root->left->right = createNode(5);
    root->right->left = createNode(6);
    root->right->right = createNode(7);

    printBoundary(root);

    return 0;
}

